---@class LFightIdleAtkActor
local LFightIdleAtkActor = LxClass("LFightIdleAtkActor",nil)
----------------------------------------------------------------
local LFightIdleSkill = LXImport("..Object.LFightIdleSkill")
----------------------------------------------------------------
function LFightIdleAtkActor:LFightIdleAtkActor(obj,manager)
	---@type LFightIdleObject
	self._obj = obj

	self._manager = manager

	self._isAttacking = false

	---@type LFightIdleSkill
	self._curSKill = nil

	---@type LFightIdleSkill[]
	self._aniFinishedSkill = {}

	---@type table<number>
	self._skillCdMap = {}
end


function LFightIdleAtkActor:OnRun(time)
	self:RunAniFinishedSkill(time)

	if not self._isAttacking then return end
	local curSkill = self._curSKill

	if not curSkill then
		self:StopAtk()
		return
	end

	if not curSkill:OnRun(time) then
		self:StopAtk()
		return
	end

	if curSkill:IsAniFinished() then
		self:StopAtk()
		table.insert(self._aniFinishedSkill,curSkill)
		self._curSKill = nil
	end
end

--执行需要循环的技能
function LFightIdleAtkActor:RunAniFinishedSkill(time)
	local aniFinishedSkill = self._aniFinishedSkill
	if not aniFinishedSkill then return end

	if #aniFinishedSkill <= 0 then return end
	local delIndex = {}
	for k,v in ipairs(aniFinishedSkill) do
		if not v:OnRun(time) then
			v:Destroy()
			table.insert(delIndex,k)
		end
	end
	for k=#delIndex,1,-1 do
		table.remove(aniFinishedSkill,delIndex[k])
	end
end

--选择一个技能
function LFightIdleAtkActor:GetASkillData()
	local obj = self._obj

	local skillList = obj:GetSkillList()
	local okSkillList = {}
	if skillList and #skillList > 0 then
		local skillCdMap = self._skillCdMap
		local time = self:GetTime()
		for k,v in ipairs(skillList) do
			local endCd = skillCdMap[v:GetSkillRefId()] or 0
			if endCd < time then
				table.insert(okSkillList,v)
			end
		end
	end

	if #okSkillList > 0 then
		return okSkillList[LFightIdleConst.RandInteger(#okSkillList)]
	else
		return obj:GetCommonSkill()
	end
end

function LFightIdleAtkActor:GetTarSkill(skillExpressId)
	local obj = self._obj
	local skillList = obj:GetSkillList()

	if skillList then
		for k,v in ipairs(skillList) do
			if v:GetExpressId() == skillExpressId then
				return v
			end
		end
	end

	local commonSkill = obj:GetCommonSkill()
	if commonSkill then
		if commonSkill:GetExpressId() == skillExpressId then
			return commonSkill
		end
	end
end

function LFightIdleAtkActor:DoAtk(targetSkill,targetNum)
	self._isAttacking = true

	local skill = self._curSKill
	if skill then
		skill:Destroy()
	end

	local obj = self._obj

	local tarObjKey = obj:GetTarObjKey()
	local objCtrl = self._manager:GetObjCtrl()
	local tarObj = objCtrl:GetObjByKey(tarObjKey)
	local tarPos = tarObj:GetPosition()
	obj:ChangeDirToPos(tarPos)

	local skillData = nil
	if targetSkill then
		skillData = self:GetTarSkill(targetSkill)
	else
		skillData = self:GetASkillData()
	end

	if not skillData then
		--printErrorN("not skill data expressId "..(targetSkill or "nil"))
		return
	end


	local skill = LFightIdleSkill:New(obj,skillData,self._manager)

	if obj:GetObjType() == LFightIdleConst.OBJ_HERO then
		local speedUp = obj:GetAttSpeedUp()
		skill:EnableSpeedUp(speedUp ~= 1 and speedUp > 0,obj:GetAttSpeedUp())
	end

	self._skillCdMap[skillData:GetSkillRefId()] = self:GetTime() + obj:GetAtkSpeed()

	self._curSKill = skill

	--设置目标

	local calcData = skillData:GetSkillCalcData()
	local targetNum =targetNum or calcData.targetNum

	local tarList = {tarObj}

	local pos = obj:GetPosition()

	local dir = obj:GetDirection()

	if pos.x < tarPos.x then
		dir = LFightIdleConst.DIRECTION_RIGHT
	elseif pos.x > tarPos.x then
		dir = LFightIdleConst.DIRECTION_LEFT
	end

	local bCheckDir = obj:GetDirectOnHook() > 0

	local objBoardRefId = obj:GetBoardRefId()
	if targetNum > 1 then
		local dicHadIn = {}
		dicHadIn[tarObjKey] = true
		local nowNum = 1
		local teamList = objCtrl:GetOppositeTeamBySide(self._obj:GetSide())

		for k,v in ipairs(teamList) do
			local objKey = v:GetObjectKey()
			if v:IsLive() and not dicHadIn[objKey] then
				local tarPos = v:GetPosition()
				if v:GetBoardRefId() == objBoardRefId and
					(not bCheckDir or self:CheckPosInDir(dir,pos,tarPos)) and
					self:CheckCanAtk(obj,v,pos,tarPos) then
					table.insert(tarList,v)
					dicHadIn[objKey] = true
					nowNum = nowNum + 1
					if nowNum >= targetNum then break end

				end
			end
		end


		--群攻改成只对当前平台有效

		--if nowNum < targetNum then
		--	for k,v in ipairs(teamList) do
		--		local objKey = v:GetObjectKey()
		--		if not dicHadIn[objKey] and v:IsLive() then
		--			table.insert(tarList,v)
		--			dicHadIn[objKey] = true
		--			nowNum = nowNum + 1
		--			if nowNum >= targetNum then break end
		--		end
		--	end
		--end

	end

	skill:SetTarList(tarList)

	skill:Start()

	if obj:GetObjType() == LFightIdleConst.OBJ_HERO then
		local logCtrl = self._manager:GetLogCtrl()
		if logCtrl then
			logCtrl:LogHeroUseSkill(obj,skillData)
		end
	end
end

function LFightIdleAtkActor:CheckCanAtk(obj,tarObj,pos,tarPos)
	local atkDis = obj:GetAtkDis() + tarObj:GetBodyX()
	local dis = Mathf.Abs(tarPos.x - pos.x)
	if LFightIdleConst.Approximately(dis, atkDis) or dis < atkDis then
		return true
	end
	return false
end

function LFightIdleAtkActor:CheckPosInDir(compDir,comPos,tarPos)
	local dir = compDir
	if tarPos.x > comPos.x then
		dir = LFightIdleConst.DIRECTION_RIGHT
	elseif tarPos.x < comPos.x then
		dir = LFightIdleConst.DIRECTION_LEFT
	end
	return dir == compDir
end

function LFightIdleAtkActor:StopAtk()
	if(not self._isAttacking) then return end
	self._isAttacking = false
end

function LFightIdleAtkActor:IsAttacking()
	return self._isAttacking
end

function LFightIdleAtkActor:GetTime()
	return self._manager:GetTime()
end

function LFightIdleAtkActor:Destroy()
	local skill = self._curSKill
	if skill then
		skill:Destroy()
	end
	for k,v in ipairs(self._aniFinishedSkill) do
		v:Destroy()
	end
	table.removeall(self)
end

return LFightIdleAtkActor